  ('franks-redhot-creamy-garlic-egg-mcmuffin-canadian-bacon-4', 'franks-redhot-creamy-garlic-egg-mcmuffin', 'Canadian Bacon', 'Pork, Water, Sugar, Salt, Sodium lactate, Sodium phosphate, Natural flavour (vegetable source), Sodium diacetate, Sodium nitrite, Smoke.', 4),
  ('franks-redhot-creamy-garlic-egg-mcmuffin-egg-5', 'franks-redhot-creamy-garlic-egg-mcmuffin', 'Egg', 'Egg (Canada A grade large), cooked on a grill, lightly seasoned, with clarified butter (unsalted butter).', 5),
