insert into menu_items (id, restaurant_id, name, category, description, ingredient_statement, sort_order) values
  ('starbucks-egg-pesto-and-mozzarella-sandwich-2123885', 'starbucks-canada', 'Egg, Pesto & Mozzarella Sandwich', 'Breakfast', 'Fluffy, cage-free egg frittata with kale, basil pesto and mozzarella on a toasted Cheddar and onion bun. An herbaceous twist on a classic egg and cheese sandwich. - HIGH-PROTEIN - VEGETARIAN', null, 1),
  ('starbucks-three-cheese-and-egg-sandwich-873068740', 'starbucks-canada', 'Three Cheese & Egg Sandwich', 'Breakfast', 'Cage-free egg frittata made with Parmesan and Monterey cheese, topped with sharp Cheddar cheese on an artisan roll. - VEGETARIAN - HIGH-PROTEIN', null, 2),
  ('starbucks-bacon-gouda-and-egg-sandwich-369', 'starbucks-canada', 'Bacon, Gouda & Egg Sandwich', 'Breakfast', 'Sizzling applewood-smoked bacon, Parmesan cage-free egg frittata and melted aged Gouda on an artisan roll. - HIGH-PROTEIN', null, 3),
  ('starbucks-bacon-style-turkey-cheddar-and-egg-white-sandwich-368', 'starbucks-canada', 'Bacon-Style Turkey, Cheddar & Egg White Sandwich', 'Breakfast', 'Your favourite sandwich just got better. Get 17g of protein now with our classic cage-free egg whites and new premium cherrywood-smoked turkey bacon, topped with a more flavourful sharp white Cheddar, inside a wheat English muffin for fuel without compromise. - HIGH-PROTEIN', null, 4),
  ('starbucks-sausage-cheddar-and-egg-sandwich-367', 'starbucks-canada', 'Sausage, Cheddar & Egg Sandwich', 'Breakfast', 'A savory sausage patty, fluffy cage-free eggs and aged Cheddar cheese on a perfectly toasted English muffin. - HIGH-PROTEIN', null, 5),
  ('starbucks-double-smoked-bacon-cheddar-and-egg-sandwich-2121219', 'starbucks-canada', 'Double-Smoked Bacon, Cheddar & Egg Sandwich', 'Breakfast', 'Bacon smoked for six hours over hickory wood chips, stacked with a cage-free fried egg, topped with a melted slice of sharp Cheddar cheese-all on our signature croissant bun. - HIGH-PROTEIN', 'Croissant (Wheat Flour, Water, Butter (Pasteurized Cream), Sugar, Yeast, Salt, Liquid Whole Eggs, Malted Barley, Dough Conditioner (Wheat Gluten, Xanthan Gum, Ascorbic Acid, Enzymes (Xylanase And Alpha Amylase)), Fried Egg Patty (Liquid Egg Whites, Liquid Egg Yolks, Whole Milk, Modified Corn Starch, Salt, Citric Acid), Bacon (Pork, Water, Salt, Sugar, Smoke Flavouring, Sodium Diacetate, Sodium Phosphate, Sodium Erythorbate, Flavouring, Sodium Nitrite), Sharp Cheddar Cheese (Pasteurized Milk, Microbial Cheese Culture, Salt, Microbial Enzymes, Annato (Vegetable Colour)))', 6),
  ('starbucks-everything-croissant-and-roasted-ham-sandwich-2123065', 'starbucks-canada', 'Everything Croissant & Roasted Ham Sandwich', 'Breakfast', 'Roasted ham combined with a cage-free fried egg patty and topped with a melted slice of Cheddar cheese in the middle of an everything croissant. - HIGH-PROTEIN', null, 7),
  ('starbucks-avocado-spread-2122257', 'starbucks-canada', 'Avocado Spread', 'Breakfast', 'Spruce up your sandwich or sous vide egg bites with avocado mixed with a touch of spices and lime. This Avocado Spread is made using a high-pressure process designed to maintain freshness without the use of heat, additives or preservatives.', 'HASS AVOCADO, SEA SALT, ONION, GARLIC, JALAPENO PEPPER, LIME JUICE', 8),
  ('starbucks-bacon-sausage-and-egg-wrap-2123181', 'starbucks-canada', 'Bacon, Sausage & Egg Wrap', 'Breakfast', 'Double-smoked bacon, savoury pork sausage and cage-free scrambled eggs combined with Cheddar cheese and potatoes-all wrapped in a flour tortilla. - HIGH-PROTEIN', null, 9),
  ('starbucks-spinach-feta-and-cage-free-egg-white-wrap-371', 'starbucks-canada', 'Spinach, Feta and Cage Free Egg White Wrap', 'Breakfast', 'Cage-free egg whites are combined with spinach, feta cheese and sun-dried tomato cream cheese inside a whole-wheat wrap. - VEGETARIAN - HIGH-PROTEIN', null, 10),
  ('starbucks-bacon-and-gruyere-egg-bites-2122116', 'starbucks-canada', 'Bacon & Gruyere Egg Bites', 'Breakfast', 'Applewood-smoked bacon and aged Gruyere and Monterey Jack cheeses folded into cage-free eggs and cooked using the French "sous vide" technique to create a velvety texture that''s full of flavour. - HIGH-PROTEIN', 'Liquid whole EGG (EGG, citric acid), Cheese blend (monterey jack cheese (pasteurized milk, bacterial culture, salt, microbial enzymes), gruyere cheese (pasteurized milk, bacterial culture, salt, microbial enzymes), potato starch, natamycin (a natural mould inhibitor)), Cottage cheese (cultured skim milk, milk, skim milk, whey, salt, maltodextrin, citric acid, carrageenan, mono- and diglycerides, locust bean gum, guar gum, natural flavour, vitiamin A palmitate, carbon dioxide (to maintain freshness), microbial enzymes), Pork bacon (cured with: water, sea salt, cane sugar, cultured celery juice, cherry powder), Flavoured butter, Corn starch, Rice starch, White vinegar (diluted with water to 4% acidity), Hot sauce (distilled vinegar, red pepper, salt), Salt, Canola oil.', 11),
  ('starbucks-egg-white-and-roasted-red-pepper-egg-bites-2122117', 'starbucks-canada', 'Egg White & Roasted Red Pepper Egg Bites', 'Breakfast', 'Cage-free egg whites combined with Monterey Jack cheese, spinach and fire-roasted red peppers and cooked using the French "sous vide" to create a velvety texture that''s full of flavour. - VEGETARIAN - HIGH-PROTEIN', 'Liquid Egg Whites, Cottage Cheese (Cultured Skim Milk, Milk, Skim Milk, Whey, Salt, Maltodextrin, Citric Acid, Carrageenan, Mono And Diglycerides, Locust Bean Gum, Guar Gum, Natural Flavour, Vitamin A Palmitate, Carbon Dioxide (To Maintain Freshness), Microbial Enzymes, Monterey Jack Cheese (Pasteurized Milk, Bacterial Culture, Salt, Microbial Enzymes, Potato Starch, Powdered Cellulose, Natamycin (A Natural Mould Inhibitor)), Red Bell Pepper, Rice Starch, Flavoured Butter, Spinach, Canola Oil, Feta Cheese (Pasteurized Milk, Bacterial Culture, Lipase, Chymosin, Potato Starch), Green Onion, Salt, Hot Sauce (Distilled Vinegar, Red Pepper, Salt), Spice)', 12),
  ('starbucks-potato-cheddar-and-chive-bakes-2123269', 'starbucks-canada', 'Potato, Cheddar & Chive Bakes', 'Breakfast', 'A mixture of potatoes, Cheddar cheese, spinach, onions and a touch of chives with cage-free eggs baked until golden brown. A savoury meal sure to take you to your happy place. - VEGETARIAN - HIGH-PROTEIN - CAGE-FREE', 'Diced potatoes (potatoes, disodium dihydrogen phosphate (to maintain colour)), Liquid whole eggs (eggs, citric acid, water), Cottage cheese (cultured skim milk, milk, skim milk, whey, salt, maltodextrin, citric acid, carrageenan, mono- and diglycerides, locust bean gum, guar gum, natural flavour, vitiamin A palmitate, carbon dioxide (to maintain freshness), microbial enzymes), Cheddar cheese (cheddar cheese (cultured pasteurized milk, salt, microbial enzymes, annatto (colour)), potato starch (anti-caking agent)), Roasted onions, Cheese blend (monterey jack cheese (pasteurized milk, bacterial culture, salt, microbial enzymes), gruyere cheese (pasteurized milk, bacterial culture, salt, microbial enzymes), potato starch, natamycin (mould inhibitor)), White cheddar cheese (white cheddar cheese (pasteurized milk, bacterial culture, salt, microbial enzymes), powdered cellulose (anti-caking agent)), Spinach, Cultured butter, Chives, Rice starch, Mustard (water, mustard seeds, vinegar, salt, sodium bisulphite (preservative)), Salt, Hot sauce (distilled vinegar, red pepper, salt), White distilled vinegar (diluted with water to 4% acidity), Canola oil (canola oil, sunflower lecithin)', 13),
  ('starbucks-rolled-steel-cut-oatmeal-301', 'starbucks-canada', 'Rolled Steel-Cut Oatmeal', 'Breakfast', 'A blend of rolled and whole-grain steel-cut oats to customize your way with a selection of toppings: raisins, dried cranberries, sliced almonds, pecans, walnuts and brown sugar. - VEGETARIAN', 'WHOLE GRAIN ROLLED OATS, WHOLE GRAIN STEEL CUT OATS, WHOLE GRAIN OAT FLOUR, SALT, CALCIUM CARBONATE, GUAR GUM.', 14),
  ('starbucks-ham-and-swiss-croissant-2122132', 'starbucks-canada', 'Ham & Swiss Croissant', 'Bakery', 'Hickory-smoked ham and melted Swiss cheese enveloped in our buttery signature croissant. A French classic with savory delights and a flaky, golden crust.', null, 15),
  ('starbucks-cheese-danish-1040', 'starbucks-canada', 'Cheese Danish', 'Bakery', 'Flaky, butter croissant dough with soft, warm cheese in the center. - VEGETARIAN', 'Enriched Wheat Flour, Neufchatel Cheese (milk ingredients, salt, locust bean gum, bacterial culture), Water, Butter, Sugar, Whole Milk Powder, Liquid Whole Egg, Yeast, Sea Salt, Wheat Gluten, Sourdough (water, fermented wheat flour), Lactic acid, Ascorbic acid, Xanthan gum, Amylase, Xylanase.', 16),
  ('starbucks-butter-croissant-1033', 'starbucks-canada', 'Butter Croissant', 'Bakery', 'Classic butter croissant with soft, flaky layers and a golden-brown crust. - VEGETARIAN', 'FLOUR (WHEAT), CULTURED BUTTER (CREAM (MILK), LACTIC ACID), WATER, SUGAR, YEAST, LIQUID WHOLE EGGS, WHOLE MILK POWDER, SALT, FERMENTED DOUGH EXTRACT (WATER, FERMENTED WHEAT FLOUR), WHEAT GLUTEN, WHEAT SOURDOUGH (WATER, FERMENTED WHEAT FLOUR), XANTHAN GUM, ASCORBIC ACID, XYLANASE AND ALPHA-AMYLASE.', 17),
  ('starbucks-chocolate-croissant-1028', 'starbucks-canada', 'Chocolate Croissant', 'Bakery', 'Two generous pieces of chocolate wrapped in a butter croissant with soft, flaky layers and a golden-brown crust. - VEGETARIAN', 'FLOUR (WHEAT), CULTURED BUTTER (CREAM (MILK), LACTIC ACID), CHOCOLATE (SUGAR, UNSWEETENED CHOCOLATE, COCOA BUTTER, DEXTROSE, SOY LECITHIN (EMULSIFIER), VANILLA EXTRACT), WATER, SUGAR, YEAST, LIQUID WHOLE EGGS, WHOLE MILK POWDER, SALT, FERMENTED DOUGH EXTRACT (WATER, FERMENTED WHEAT FLOUR), WHEAT GLUTEN, WHEAT SOURDOUGH (WATER, FERMENTED WHEAT FLOUR), XANTHAN GUM, ASCORBIC ACID, XYLANASE AND ALPHA-AMYLASE.i12', 18),
  ('starbucks-belgian-liege-waffle-2124777', 'starbucks-canada', 'Belgian Liege Waffle', 'Bakery', 'Sweet, golden-brown Liege waffle infused with pearl sugar and smooth vanilla flavour.', 'Wheat flour, Butter, Sugars (pearl sugar, invert sugar), Water, Liquid eggs, Yeast, Milk powder, Salt, Natural vanilla flavour.', 19),
  ('starbucks-8-maple-mini-pancakes-2124779', 'starbucks-canada', '8 Maple Mini Pancakes', 'Bakery', 'Sweet, golden-brown, bite-size pancakes infused with maple sugar and maple flavour.', 'Enriched wheat flour, Canola oil, Sugars (sugar, maple sugar), Water, Liquid whole egg, Whey powder, Baking powder, Sunflower lecithin, Dried egg-white, Natural flavour, Salt, Citric acid.', 20),
  ('starbucks-4-maple-mini-pancakes-2124778', 'starbucks-canada', '4 Maple Mini Pancakes', 'Bakery', 'Sweet, golden-brown, bite-size pancakes infused with maple sugar and maple flavour.', null, 21),
  ('starbucks-iced-lemon-loaf-1254', 'starbucks-canada', 'Iced Lemon Loaf', 'Bakery', 'Citrusy, buttery, moist lemon pound cake topped with a sweet icing. - VEGETARIAN', 'Sugars (sugar, corn syrup), Enriched wheat flour, Liquid whole eggs, Soybean oil, Buttermilk (modified milk ingredients, modified cornstarch, sodium citrate, locust bean gum, carrageenan, mono- and diglycerides, salt, Vitamin A palmitate, Vitamin D3), Butter, Lemon zest (lemon peel, sugar, lemon oil), Water, Lemon juice, Modified milk ingredients, Concentrated lemon juice, Natural flavour, Liquid egg whites, Sea salt, Baking powder, Baking soda, Mono- and diglycerides, Guar gum, Modified Cellulose, Xanthan gum, Soy lecithin.', 22),
  ('starbucks-cinnamon-coffee-cake-1021', 'starbucks-canada', 'Cinnamon Coffee Cake', 'Bakery', 'Buttery, moist, coffee cake swirled with a cinnamon-sugar blend and finished with a crunchy streusel topping. - VEGETARIAN', 'ENRICHED WHEAT FLOUR, SUGAR, BUTTER, BROWN SUGAR, SOUR CREAM (SKIM MILK, CREAM, MILK PROTEIN CONCENTRATE, SKIM MILK POWDER, MICROBIAL ENZYME, BACTERIAL CULTURE), LIQUID WHOLE EGG, WHOLE MILK, CANOLA OIL, CINNAMON, BAKING POWDER, NATURAL FLAVOUR, SEA SALT.', 23),
  ('starbucks-banana-loaf-892', 'starbucks-canada', 'Banana Loaf', 'Bakery', 'Sweet, ripe bananas and a hint of cinnamon spice mixed into a moist, classic banana bread. - VEGETARIAN', 'BANANAS, WHEAT FLOUR, SUGAR, LIQUID WHOLE EGG, SOYBEAN AND / OR CANOLA OIL, BAKING POWDER, SEA SALT, VANILLA FLAVOUR, SPICE, SOY LECITHIN.i12', 24),
  ('starbucks-blueberry-muffin-with-yogurt-and-honey-1036', 'starbucks-canada', 'Blueberry Muffin with Yogurt & Honey', 'Bakery', 'Soft muffin with sweet, juicy blueberries, yogurt and honey-deliciously flavourful. - VEGETARIAN', 'Enriched wheat flour, Sugars (sugar, honey), Blueberries, Plain yogurt (milk ingredients, modified milk ingredients, modified cornstarch, bacterial culture), Soybean oil, Liquid whole egg, Butter, Baking powder, Modified cornstarch, Vanilla extract, Sea salt, Natural flavour, Vanilla bean pieces, Soy lecithin.', 25),
  ('starbucks-mini-dill-and-rye-bagels-36003', 'starbucks-canada', 'Mini Dill & Rye Bagels', 'Bakery', 'Three artisan rye bagel rounds crafted from a balanced blend of white and whole-wheat rye flour. Each round is generously filled with dill-infused cream cheese, brightened with a touch of lemon zest and finished with a sprinkle of toasted sesame seeds for added crunch and flavour.', null, 26),
  ('starbucks-frog-cake-pop-28400', 'starbucks-canada', 'Frog Cake Pop', 'Treats', 'Vanilla cake mixed with buttercream, dipped in green chocolaty icing and decorated as a cute frog. - VEGETARIAN', null, 27),
  ('starbucks-lemon-cake-pop-2123000', 'starbucks-canada', 'Lemon Cake Pop', 'Treats', 'Lemon-flavoured white cake enrobed in a zesty yellow, chocolaty coating and a sweet-and-sour topping. - VEGETARIAN', null, 28),
  ('starbucks-valentine-cake-pop-2122932', 'starbucks-canada', 'Valentine Cake Pop', 'Treats', 'A rich chocolate cake coated with chocolaty icing and finished with heart sprinkles. - Vegetarian', null, 29),
  ('starbucks-birthday-cake-pop-784', 'starbucks-canada', 'Birthday Cake Pop', 'Treats', 'Bite-sized vanilla cake mixed with vanilla buttercream, dipped in pink chocolaty icing and topped with white sprinkles. - VEGETARIAN', null, 30),
  ('starbucks-chocolate-cake-pop-1015', 'starbucks-canada', 'Chocolate Cake Pop', 'Treats', 'Bite-sized chocolate cake mixed with chocolate buttercream, dipped in chocolaty icing and topped with white sprinkles. - VEGETARIAN', null, 31),
  ('starbucks-heart-cookie-2122140', 'starbucks-canada', 'Heart Cookie', 'Treats', 'A rich, buttery heart-shaped cookie topped with white or pink chocolaty coating and colourful sprinkles. - VEGETARIAN', null, 32),
  ('starbucks-double-chocolate-brownie-299', 'starbucks-canada', 'Double Chocolate Brownie', 'Treats', 'Rich chocolate brownie with generous chunks of semisweet chocolate. - VEGETARIAN', 'SUGAR, WHEAT FLOUR, WHOLE LIQUID EGGS, CANOLA OIL, MILK CHOCOLATE (SUGAR, COCOA BUTTER, BELGIAN UNSWEETENED CHOCOLATE, MODIFIED MILK PRODUCT, SOY LECITHIN, VANILLA EXTRACT), SEMI-SWEET CHOCOLATE (UNSWEETENED CHOCOLATE, SUGAR, SOY LECITHIN), SEMI-SWEET CHOCOLATE CHUNKS (SUGAR, CHOCOLATE LIQUOR, COCOA BUTTER, ANHYDROUS DEXTROSE, SOY LECITHIN, VANILLA), CHOCOLATE LIQUOR, BROWN RICE SYRUP, SEMI-SWEET CHOCOLATE CHIPS (SUGAR, CHOCOLATE LIQUOR PROCESSED WITH ALKALI, COCOA BUTTER, MILK FAT, SOY LECITHIN, VANILLA), SALTED BUTTER, WHIPPING CREAM (CREAM, CARRAGEENAN), WATER, BAKING POWDER, SALT, VANILLA EXTRACT, MALTITOL SYRUP.i12', 33),
  ('starbucks-chocolate-chunk-cookie-1030', 'starbucks-canada', 'Chocolate Chunk Cookie', 'Treats', 'Semisweet chocolate chunks mixed in a thick, chewy cookie-soft on the inside and crunchy on the outside. - VEGETARIAN', 'SEMI-SWEET CHOCOLATE CHUNKS (SUGAR, CHOCOLATE LIQUOR, DEXTROSE, COCOA BUTTER, SOY LECITHIN, VANILLA EXTRACT), WHEAT FLOUR, BUTTER (BARLEY), BROWN SUGAR, SUGAR, LIQUID WHOLE EGGS, VANILLA EXTRACT, SODIUM BICARBONATE, SALT.', 34),
  ('starbucks-ginger-molasses-cookie-537', 'starbucks-canada', 'Ginger Molasses Cookie', 'Treats', 'Ginger and molasses mixed in a supersoft chewy cookie. - VEGETARIAN', 'WHEAT FLOUR, SUGAR, MOLASSES, BUTTER, INVERT SUGAR, LIQUID WHOLE EGGS, SODIUM BICARBONATE, SPICES, BAKING POWDER.', 35),
  ('starbucks-oat-bar-539', 'starbucks-canada', 'Oat Bar', 'Treats', 'Hearty rolled Canadian oats and perfectly creamy butter mixed together to make a chewy oat bar. - VEGETARIAN', 'oats, butter (milk), corn syrup, brown sugar, vanilla flavour, salt.', 36),
  ('starbucks-ham-and-swiss-on-baguette-574', 'starbucks-canada', 'Ham & Swiss on Baguette', 'Lunch', 'Ham and Swiss cheese meld with Dijon butter on a toasted baguette. - HIGH-PROTEIN', null, 37),
  ('starbucks-chicken-and-bacon-on-brioche-2121995', 'starbucks-canada', 'Chicken & Bacon on Brioche', 'Lunch', 'Herbed, slow-cooked, white meat chicken, double-smoked bacon, maple mustard and cheese piled high on toasted apple brioche. - HIGH-PROTEIN', null, 38),
  ('starbucks-crispy-grilled-cheese-on-sourdough-2122717', 'starbucks-canada', 'Crispy Grilled Cheese on Sourdough', 'Lunch', 'A blend of mild Cheddar and baby Gouda cheeses on sourdough bread, topped with an olive-oil butter spread. - VEGETARIAN - HIGH-PROTEIN', null, 39),
  ('starbucks-tomato-and-mozzarella-on-focaccia-573', 'starbucks-canada', 'Tomato & Mozzarella on Focaccia', 'Lunch', 'Roasted tomatoes, mozzarella, spinach and basil pesto layered on toasted focaccia bread. - VEGETARIAN - HIGH-PROTEIN', null, 40),
  ('starbucks-turkey-provolone-and-pesto-on-ciabatta-2121962', 'starbucks-canada', 'Turkey, Provolone & Pesto on Ciabatta', 'Lunch', 'Thick-sliced turkey breast, melted provolone cheese, dry-roasted red peppers and basil pesto on a ciabatta roll. - HIGH-PROTEIN', null, 41),
  ('starbucks-spicy-falafel-pocket-2124655', 'starbucks-canada', 'Spicy Falafel Pocket', 'Lunch', 'Smashed falafel, creamy hummus, roasted red bell peppers, pickled onions and a spicy herb sauce wrapped inside a toasted lavash flatbread. - VEGAN', null, 42),
  ('starbucks-jalapeno-chicken-pocket-2124812', 'starbucks-canada', 'Jalapeno Chicken Pocket', 'Lunch', 'A toasted chile lavash flatbread wrapped and stuffed with diced chicken, charred poblanos, green jalapenos, three-chile-pepper cheese and jalapeno cream cheese.', null, 43),
  ('starbucks-original-hummus-and-crackers-snack-box-2123772', 'starbucks-canada', 'Original Hummus & Crackers Snack Box', 'Lunch', 'Chickpeas and tahini blended with garlic and lemon juice, paired with crisp flatbread crackers. - VEGAN', null, 44),
  ('starbucks-artisan-charcuterie-snack-box-2123423', 'starbucks-canada', 'Artisan Charcuterie Snack Box', 'Lunch', 'Artisan dry-cured salami and creamy fontinello cheese paired with bite-size breadsticks.', null, 45),
  ('starbucks-apples-pb-and-trail-mix-snack-box-2123507', 'starbucks-canada', 'Apples, PB & Trail Mix Snack Box', 'Lunch', 'Apple slices and Justin''s peanut butter paired with a blend of almonds, chocolate chunks, dried cranberries, pumpkin seeds, cashews, currants and raisins. - VEGAN - VEGETARIAN', null, 46),
  ('starbucks-mid-day-squares-peanut-butta-2123878', 'starbucks-canada', 'Mid-Day Squares Peanut Butta', 'Lite Bites', 'Designed to stop your mid-day cravings, this peanut butter plant-based square is made from natural ingredients and contains 6 g of protein, high fibre and Fairtrade dark chocolate to fuel your on-the-go lifestyle. - VEGAN', null, 47),
  ('starbucks-mid-day-squares-cookie-dough-2123884', 'starbucks-canada', 'Mid-Day Squares Cookie Dough', 'Lite Bites', 'Designed to stop your mid-day cravings, this cookie dough plant-based square is made from natural ingredients and contains 6 g of protein, high fibre and Fairtrade dark chocolate to fuel your on-the-go lifestyle. - VEGAN', null, 48),
  ('starbucks-butter-gourmet-popcorn-2121689', 'starbucks-canada', 'Butter Gourmet Popcorn', 'Lite Bites', 'Perfectly buttery with just the right amount of salt, this fluffy snack favorite makes movie theaters everywhere jealous.', null, 49),
  ('starbucks-perfectly-salted-kettle-potato-chips-2121813', 'starbucks-canada', 'Perfectly Salted Kettle Potato Chips', 'Lite Bites', 'Kettle potato chips perfectly salted for a naturally delicious snack with undeniable flavour and crunch.', null, 50),
  ('starbucks-squirrel-classic-almonds-2121742', 'starbucks-canada', 'Squirrel - Classic Almonds', 'Lite Bites', 'Pure California almonds are kettle-cooked, then finished with a hint of salt.', null, 51),
  ('starbucks-madeleines-2121740', 'starbucks-canada', 'Madeleines', 'Lite Bites', 'Made with quality ingredients, these rich and buttery French cakes are soft and moist in the center and baked with lightly crisped edges.', null, 52),
  ('starbucks-squirrel-brand-creme-brulee-almonds-2121743', 'starbucks-canada', 'Squirrel Brand - Creme Brulee Almonds', 'Lite Bites', 'Pure California almonds are kettle-cooked, then finished with a thin layer of caramelized sugar. A crunchy, bite-sized substitute for the famous dessert.', null, 53),
  ('starbucks-gluten-free-marshmallow-dream-bar-309', 'starbucks-canada', 'Gluten-Free Marshmallow Dream Bar', 'Lite Bites', 'This crispy, chewy marshmallow bar, made of ooey-gooey, soft marshmallows, crispy rice, creates a sweet treat that''ll make you snack like a kid again.', null, 54),
  ('starbucks-justin-s-dark-chocolate-peanut-butter-cups-2121686', 'starbucks-canada', 'Justin''s Dark Chocolate Peanut Butter Cups', 'Lite Bites', 'What happens when the best-tasting peanut butter in the world is delicately placed into the highest-quality, dark chocolate available? Peanut-butter cup perfection.', null, 55),
  ('starbucks-crispy-apple-chips-2123148', 'starbucks-canada', 'Crispy Apple Chips', 'Lite Bites', 'Enjoy a healthy snack that''s all apple with just a dash of indulgence. One that tastes and sounds great!', null, 56),
  ('starbucks-marble-cheese-stick-2122137', 'starbucks-canada', 'Marble Cheese Stick', 'Lite Bites', 'Marble cheese is delicious on its own as a snack or added to your lunch. This on-the-go cheese stick is protein-packed, kid-approved and colourful too.', null, 57)
